283→    /**
284→     * 非对称解密，默认 value 是 base64_encode 过的.
285→     *
286→     * @param string $value
287→     * @param string $privateKey
288→     * @return null|string
289→     */
290→    public function decryptByRsa(string $value, string $privateKey = ''): ?string
291→    {
292→        if ($value === '') { // 空值不必解密
293→            return '';
294→        }
295→
296→        $privateKey = empty($privateKey) ? file_get_contents(base_path(config('my_project.RSA_private_key'))) : $privateKey;
297→        openssl_private_decrypt(base64_decode($value), $decryptedValue, $privateKey);
298→        return $decryptedValue;
299→    }
