26→    public function __construct(string $message = '', int $code = self::ERR_CRYPTO, ?Throwable $previous = null)
27→    {
28→        $backtrace = debug_backtrace(DEBUG_BACKTRACE_IGNORE_ARGS, 2);
29→        $preCaller = end($backtrace);
30→
31→        $class = '';
32→        if (isset($preCaller['class'])) {
33→            $lastSlashPos = strrpos($preCaller['class'], '/');
34→            $class = ($lastSlashPos === false) ? $preCaller['class'] : substr($preCaller['class'], $lastSlashPos);
35→        }
36→        $method = $class.'::'.$preCaller['function'];
37→        $message = $method.' '.$message;
38→
39→        parent::__construct($message, $code, $previous);
40→    }
