42→    /**
43→     * 将 code 精简为三位数，用于解密失败时拼接到密文中，供前端参考。
44→     *
45→     * @param int $code 原始的异常错误码
46→     * @return int 转换后的三位 code，返回 0 表示不拼接错误码
47→     */
48→    public static function shortenCode(int $code): int
49→    {
50→        // 旧版代码中提到 openssl 失败不拼接错误码，因此这里返回 0
51→        if ($code === self::ERR_OPENSSL_DECRYPT_FAILED) {
52→            return 0;
53→        }
54→
55→        if ($code < 100) {
56→            return 100;
57→        }
58→
59→        return $code % 1000;
60→    }
61→}
