     * 往绩效记录中追加员工的花名。
     *
     * @param array $performances
     * @param string $userIdKey
     * @return array
     */
    public function normalize(array $performances, string $userIdKey = 'user_id'): array
    {
        $sfusers = Sfuser::whereIn('id', collect($performances)->pluck($userIdKey))->pluck('nickname', 'id')->toArray();
        return array_map(function ($item) use ($sfusers, $userIdKey) {
            $item = (array)$item;
            if (Arr::has($item, 'publisher_id')) {
                // 如果给了 publisher id，混淆一下
                $item['publisher_id'] = PerformanceUtil::encrypt($item['publisher_id']);
            }
            $item['user_nickname'] = Arr::get($sfusers, $item[$userIdKey] ?? 0, '');
            $item['site'] = config('my_project.site_key');
            return $item;
        }, $performances);
    }

    private function getCondition(Request $request): array
    {
        // 驳回一组的话，如果当前地区不存在，则只更新
        $condition = $request->only([
            'performance_gid', 'appraiser_id',
        ]);
        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
        $condition['year'] = $year;
        $condition['month'] = $month;
        return $condition;
    }

    /**
     * @noinspection all
     * @param Request $request
     * @return null|\Illuminate\Database\Eloquent\Builder|\Illuminate\Database\Eloquent\Model|object
     */
    private function getPublisherGroup(Request $request)
    {
        return PerformanceGroup::where($this->getCondition($request))->first();
    }
}

