601→     * @return JsonResponse
602→     */
603→    public function submitAppraisals(Request $request): JsonResponse
604→    {
605→        if (($code = $this->service->determineIfCanBeSubmitted($request->all())) != PerformanceService::ERR_OK) {
606→            return $this->responseJsonFail(__('performance_api.performance_cannot_submit_appraisal', ['code' => $code, 'msg' => PerformanceService::MESSAGE[$code] ?? '']));
607→        }
608→
609→        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
610→        $condition = [
611→            'year' => $year,
612→            'month' => $month,
613→            'appraiser_id' => Auth::id(),
614→        ];
615→
616→        db()->beginTransaction();
617→
618→        $count = 0;
619→        try {
620→            // 本地区的分组表里更新下统计数据
621→            $pgs = $request->input('pgs');
622→            foreach ($pgs as $pg) {
623→                if (Auth::belongsToCurrentSite()) {
624→                    /** @var null|Performance $p */
625→                    $p = PerformanceGroup::where($condition)->where('performance_gid', $pg['performance_gid'])->first();
626→                    if (empty($p)) {
627→                        continue;
628→                    }
629→
630→                    if ($p->expiration_status != Performance::EXPIRATION_STATUS_DEFAULT) {
631→                        throw new ResourceException(__('performance_api.performance_expired'));
632→                    }
633→
634→                    // 给前端的是加密的，得先解密（为了避免暴露 id->nickname 的映射）
635→                    $publisherId = PerformanceUtil::decrypt($pg['publisher_id'] ?? '');
636→                    PerformanceGroup::where($condition)
637→                        ->where('performance_gid', $pg['performance_gid'])
638→                        // 不再单独维护提交状态
639→                        ->update(Arr::only($pg, ['total_count', 'unqualified_count']) + [
640→                            'publisher_id' => $publisherId,
641→                            'status' => Performance::STATUS_SUBMITTED,
642→                        ]);
643→                }
644→
645→                // 产品要求可以一组一组提交，因此不能直接更新所有的绩效
646→                $count += Performance::where($condition)
647→                    ->whereIn('status', [Performance::STATUS_NOT_SUBMITTED, Performance::STATUS_REJECTED])
648→                    ->where('expiration_status', Performance::EXPIRATION_STATUS_DEFAULT)
649→                    ->where('performance_gid', $pg['performance_gid'])
650→                    ->update(['status' => Performance::STATUS_SUBMITTED]);
651→            }
652→            db()->commit();
653→        } catch (\Throwable $e) {
654→            Log::error('failed to commit transaction', ['e' => $e->getMessage()]);
655→            db()->rollBack();
656→            throw new ServerException(ServerException::ERR_SERVER_DATABASE);
657→        }
658→
659→        // refresh current user's stat info at current site
660→        PerformanceStatCache::app()->refreshOne(PerformanceStatCache::TYPE_APPRAISER, Auth::id(), $year, $month);
661→
662→        return $this->responseJsonSuccess(['count' => $count]);
663→    }
