 * @throws \Throwable
 * @return JsonResponse
 */
public function submitAppraisals(Request $request): JsonResponse
{
    if (($code = $this->service->determineIfCanBeSubmitted($request->all())) != PerformanceService::ERR_OK) {
        return $this->responseJsonFail(__('performance_api.performance_cannot_submit_appraisal', ['code' => $code, 'msg' => PerformanceService::MESSAGE[$code] ?? '']));
    }

    [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
    $condition = [
        'year' => $year,
        'month' => $month,
        'appraiser_id' => Auth::id(),
    ];

    db()->beginTransaction();

    $count = 0;
    try {
        // 本地区的分组表里更新下统计数据
        $pgs = $request->input('pgs');
        foreach ($pgs as $pg) {
            if (Auth::belongsToCurrentSite()) {
                /** @var null|Performance $p */
                $p = PerformanceGroup::where($condition)->where('performance_gid', $pg['performance_gid'])->first();
                if (empty($p)) {
                    continue;
                }

                if ($p->expiration_status != Performance::EXPIRATION_STATUS_DEFAULT) {
                    throw new ResourceException(__('performance_api.performance_expired'));
                }

                // 给前端的是加密的，得先解密（为了避免暴露 id->nickname 的映射）
                $publisherId = PerformanceUtil::decrypt($pg['publisher_id'] ?? '');
                PerformanceGroup::where($condition)
                    ->where('performance_gid', $pg['performance_gid'])
                    // 不再单独维护提交状态
                    ->update(Arr::only($pg, ['total_count', 'unqualified_count']) + [
                        'publisher_id' => $publisherId,
                        'status' => Performance::STATUS_SUBMITTED,
                    ]);
            }

            // 产品要求可以一组一组提交，因此不能直接更新所有的绩效
            $count += Performance::where($condition)
                ->whereIn('status', [Performance::STATUS_NOT_SUBMITTED, Performance::STATUS_REJECTED])
                ->where('expiration_status', Performance::EXPIRATION_STATUS_DEFAULT)
                ->where('performance_gid', $pg['performance_gid'])
                ->update(['status' => Performance::STATUS_SUBMITTED]);
        }
        db()->commit();
    } catch (\Throwable $e) {
        Log::error('failed to commit transaction', ['e' => $e->getMessage()]);
        db()->rollBack();
        throw new ServerException(ServerException::ERR_SERVER_DATABASE);
    }

    // refresh current user's stat info at current site
    PerformanceStatCache::app()->refreshOne(PerformanceStatCache::TYPE_APPRAISER, Auth::id(), $year, $month);

    return $this->responseJsonSuccess(['count' => $count]);
}

