public function appraisalsWorkflows(Request $request): JsonResponse
{
    $input = $request->only(['per_page']) + ['per_page' => 20];

    $data = PerformanceWorkflow::active()->where('user_id', Auth::id())
        ->with('operations')
        ->where('type', PerformanceWorkflow::TYPE_MEMBER_ALTERNATION)
        ->select(
            'id',
            'user_id',
            'approver_id',
            'type',
            'data',
            'info',
            'status',
            'remark',
            // 我发起的不需要 token
            // 'token',
            'created_at',
            'updated_at'
        )
        ->orderBy('updated_at', 'desc') // 按照创建时间逆序排序
        ->paginate($input['per_page'])
        ->toArray();

    $workflows = [
        'current_page' => $data['current_page'],
        'last_page' => $data['last_page'],
        'total' => $data['total'],
        'workflows' => $data['data'],
    ];

    return $this->responseJsonSuccess($workflows);
}

/**
 * 绩效处理列表。
 *
 * @param Request $request
 * @return JsonResponse
 */
public function approvingWorkflows(Request $request): JsonResponse
{
    $input = $request->only(['per_page', 'type', 'types', 'status', 'statuses']) + ['per_page' => 20];
    $data = PerformanceWorkflow::with('user:id,nickname')
        ->where('status', '<>', PerformanceWorkflow::STATUS_INIT)
        ->where('is_closed', 0)->where('approver_id', Auth::id())
        ->with('operations')
        ->select(
            'id',
            'user_id',
            'approver_id',
            'type',
            'data',
            'info',
            'status',
            'remark',
            'token',
            'created_at',
            'updated_at',
            'is_read'
        );

    if (Arr::has($input, 'status')) {
        $data->where('status', $input['status']);
    }

    if (Arr::has($input, 'statuses')) {
        $data->whereIn('status', $input['statuses']);
    }

    if (Arr::has($input, 'type')) {
        $data->where('type', $input['type']);
    }

    if (Arr::has($input, 'types')) {
        $data->whereIn('type', $input['types']);
    }

    $data = $data->orderByDesc('id')->paginate($input['per_page'])
        ->toArray();

    $records = $data['data'];
    $tokens = [];

    // 前端需要评价人的信息
    foreach ($records as $k => &$record) {
        if ($record['token'] ?? '') {
            $tokens[] = $record['token'];
            unset($record['token']);
            $record['user_nickname'] = Arr::get($record, 'user.nickname', '');

            if ($record['type'] == PerformanceWorkflow::TYPE_PERFORMANCE_APPEAL) {
                // 绩效申诉
                $performanceId = Arr::get($record, 'data.performance_id', 0);
                $performance = Performance::find($performanceId);
                $record['data']['performance'] = $performance->toArray();
            }

            unset($record['user']);
        } else {
            // no token, should not be passed to frontend may be?
            unset($records[$k]);
        }
    }

    $workflows = [
        'current_page' => $data['current_page'],
        'last_page' => $data['last_page'],
        'total' => $data['total'],
        'workflows' => $records,
        'decrypt_config' => [
            'tokens' => $tokens,
        ],
    ];

    return $this->responseJsonSuccess($workflows);
}

