public function groupRecords(int $userId, int $publishmentId, string $publisherId): array
{
    $publisherId = PerformanceUtil::decrypt($publisherId);

    /** @var null|PerformancePublishmentToken $ppt */
    $ppt = PerformancePublishmentToken::where([
        'publisher_id' => $publisherId,
        'publishment_id' => $publishmentId,
    ])->first();

    // 本地区没有对应于该 publisher 的 publishment 的授权 token，则表示本地区没有该发布对应的记录
    if (empty($ppt) || empty($ppt->quarter_year_token)) {
        return [
            'performances' => [],
        ];
    }

    $selectedColumns = [
        'id', 'user_id', 'year', 'month', 'performance_gid', 'publishment_id',
        'score', 'content', 'appraiser_nickname', 'publisher_nickname', 'status', 'expiration_status',
    ];

    $performances = Performance::whereIn('status', Performance::USER_CAN_VIEW)
        ->where('publishment_id', $publishmentId)
        ->where('publisher_id', $publisherId)
        ->select($selectedColumns);

    return [
        'performances' => Sfuser::normalize($performances->get()->toArray(), unsetId: true),
        'decrypt_config' => [
            'tokens' => [$ppt->quarter_year_token],
        ],
    ];
}

/**
 * 更新季度 Token。
 *
 * @param int $publisherId
 * @param int $publishmentId
 * @param string $quarterToken
 * @throws \Throwable
 * @return array|int[]
 */
public function updateQuarterToken(int $publisherId, int $publishmentId, string $quarterToken): array
{
    $condition = [
        'publisher_id' => $publisherId,
        'publishment_id' => $publishmentId,
    ];
    db()->beginTransaction();
    try {
        /** @var null|PerformancePublishmentToken $performancePublishmentToken */
        $performancePublishmentToken = PerformancePublishmentToken::where($condition)->first();
        if (empty($performancePublishmentToken)) {
            // 不存在需要新建一个
            $performancePublishmentToken = PerformancePublishmentToken::create($condition);
        }
        // 更新 token 表
        $performancePublishmentToken->update([
            'quarter_year_token' => $quarterToken,
        ]);
        db()->commit();
    } catch (\Throwable $e) {
        Log::error('failed to commit transaction', [
            'e' => $e->getMessage(),
            'location' => __CLASS__.'@'.__METHOD__.'#'.__LINE__,
        ]);
        db()->rollBack();

        return [
            'publishment_id' => 0,
        ];
    }

    return [
        'publishment_id' => $performancePublishmentToken->publishment_id,
    ];
}

