            'month' => $month,
            'appraiser_id' => $appraiserId,
            'performance_gid' => $performanceGid,
        ];

        /** @var null|PerformanceGroup $pg */
        $pg = PerformanceGroup::where($condition)->first();
        if (!empty($pg)) {
            // 在当前地区存在分组
            $pg->update([
                'total_count' => $pg->total_count > 0 ? ($pg->total_count - 1) : 0,
                'unqualified_count' => $pg->unqualified_count > 0 ? ($pg->unqualified_count - ($unqualified ? 1 : 0)) : 0,
            ]);
        }
    }

    // 最后更新绩效负责人
    if (!empty($sfuser)) {
        $psm = PerformanceSpecialMap::active()->where('user_id', $userId)
            ->where('is_closed', 0)
            ->first();
        if ($source == 'staff') {  // 从员工管理入口强制刷新
            // 先要判断一下是否存在特殊配置，如果存在，则不允许更改
            if (!empty($psm)) {
                throw new ResourceException('performance special map exists.');
            }
            $newAppraiserIds[] = $sfuser->direct_supervisor_id;
            $columns = [
                'appraiser_id' => $sfuser->direct_supervisor_id,
                'publisher_id' => $sfuser->supervisor_id,
                'appraiser_nickname' => $sfuser->direct_supervisor_nickname,
                'publisher_nickname' => $sfuser->supervisor_nickname,
            ];
        } elseif ($source == 'special_map') {  // 从绩效特殊配置那里进行更新
            /** @var null|PerformanceSpecialMap $psm */
            if (empty($psm)) { // 找不到表示删除，产品要求删除时的立即生效还原为之前的直接主管或者部门主管
                $columns = [
                    'appraiser_id' => $sfuser->direct_supervisor_id,
