        if (empty($p) && !$addIfNotExists) {
            throw new ResourceException('performance record not exists.');
        }

        $updateColumns = [
            'score' => '',
            'score_hash' => '',
            'content' => '',
            'publishment_id' => 0,
            'performance_gid' => 0,
            'performance_gid_index' => 0,
        ];

        /** @var null|Performance $p */
        if (empty($p)) {
            // 数据库默认值已经设为 1 了，这里做一下双重保证
            $updateColumns['status'] = Performance::STATUS_NOT_SUBMITTED;
            // 新生成的绩效，要判断是否过了逾期的时间
            $remainDays = CalendarService::app()->currentRevRank();
            if ($remainDays <= 4) {
                // 只剩四天了，需要标记为评价逾期状态
                $updateColumns['expiration_status'] = Performance::EXPIRATION_STATUS_NO_APPRAISAL;
            }
            Log::info('create performance', [$updateColumns]);
        } else {
            $appraiserIds[] = $p->appraiser_id;
            $publisherIds[] = $p->publisher_id;
            Log::info('performance modified', [$p->toArray()]);
        }

        // 否则都直接更新绩效属性
        Performance::updateOrCreate($attributes, $columns + $updateColumns);
        // re-fetch
        $p = Performance::where($attributes)->first();
        // 如果删除特殊配置，并且不是中国站点，则删除绩效表而不是更新绩效表为直接主管/部门主管
        if ($deleteFromSpecialMap && SiteService::app()->isNot(SiteService::CHN) && !empty($p)) {
            $p->delete();
        }
    }
    if (!$preflight) {
        db()->commit();
    }
} catch (\Exception $e) {
    db()->rollBack();
    Log::error('failed to refresh user performance..', ['e' => $e->getMessage(), 'args' => func_get_args()]);
    return false;

