public function myRecords(int $userId): array
{
    // 前端不能使用 token 来获取组记录了，前端得全部换成 publisher id 获取记录，
    // 为了避免同时返回 id 和花名，将 publisher id 进行对称加密
    $selectedColumns = [
        'id', 'user_id', 'year', 'month', 'performance_gid', 'publishment_id', 'publisher_id',
        'score', 'content', 'appraiser_nickname', 'publisher_nickname', 'status', 'published_at', 'expiration_status',
    ];

    $ago = Carbon::now()->subMonths(3);
    // workflow 里标记了当前审批是否与其他的关联
    $performances = Performance::with('workflow.operations')
        ->where('user_id', $userId)
        ->where(function ($q) {
            // 既可以查看发布逾期的记录，也可以查看正常流转过程中的记录
            $q->whereIn('status', Performance::USER_CAN_VIEW)
                ->orWhere('expiration_status', Performance::EXPIRATION_STATUS_NO_PUBLISHMENT);
        })
        ->orderBy('year', 'desc')
        ->orderBy('month', 'desc')
        ->where('updated_at', '>', $ago) // 更新时间在当前三个月之前
        ->limit(3) // 最多只能查看最近三条的记录
        ->select($selectedColumns);

    $performances = $performances->get()->toArray();
    $performances = array_map(function ($item) {
        $item = (array)$item;
        // 将 publisher_id 混淆之后返回，因为 publisher_id + publishment_id 唯一确定了一组合并发布的绩效
        if (Arr::has($item, 'publisher_id')) {
            $item['publisher_id'] = PerformanceUtil::encrypt($item['publisher_id']);
        }
        $item['site'] = config('my_project.site_key');
        return $item;
    }, $performances);

    return [
        'performances' => $performances,
    ];
}

public function managementRecords(int $publishmentId): array
{
    return Performance::where([
        'publishment_id' => $publishmentId,
    ])->select(
        'id',
        'user_id',
        'year',
        'month',
        'performance_gid',
        'publishment_id',
        'score',
        'content',
        'appraiser_nickname',
        'publisher_nickname',
        'status',
    )->get()->toArray();
}

/**
 * fetch all user's performances (as normal staff), and return also the decrypt tokens!!
 *
 * @param int $userId
 * @param int $publishmentId
 * @param string $publisherId
 * @return array
 */
public function groupRecords(int $userId, int $publishmentId, string $publisherId): array
{
    $publisherId = PerformanceUtil::decrypt($publisherId);

