    /**
     * 获取绩效评价组，值得注意的是，发布人可以获取评价人设置的组，因此在绩效发布界面，需要先取出所有的组。
     *
     * @param mixed $ownerIds
     * @return array
     */
    public function groups(mixed $ownerIds): array
    {
        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
        $ownerIds = Arr::wrap($ownerIds);
        $groups = PerformanceGroup::with(['appraiser:id,nickname'])
            ->where(['year' => $year, 'month' => $month, 'is_closed' => 0])
            ->whereIn('appraiser_id', $ownerIds)
            ->get(['name', 'performance_gid', 'year', 'month', 'appraiser_id', 'publishment_id', 'unqualified_count', 'total_count', 'created_at', 'updated_at', 'status', 'is_default', 'history_remarks', 'expiration_status'])
            ->toArray();

        return array_map(function ($item) {
            // 因为评价人的组在评价人的地区，所以肯定可以获取到花名
            $item['appraiser_nickname'] = Arr::get($item, 'appraiser.nickname', '');
            $item['site'] = SiteService::app()->site();
            unset($item['appraiser']);
            return $item;
        }, $groups);
    }

    public function createGroups(array $groups, int $userId): bool
    {
        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
        $maxGid = PerformanceGroup::whereAppraiserId($userId)->max('performance_gid');
        $currentGid = $maxGid + 1;
        // 新生成的绩效，要判断是否过了逾期的时间
        $remainDays = CalendarService::app()->currentRevRank();

        $exists = PerformanceGroup::where([
            'appraiser_id' => $userId,
            'is_default' => 1,
            'is_closed' => 0,
            'year' => $year,
            'month' => $month,
        ])->exists();

        $now = Carbon::now();
        $columns = [];
        foreach ($groups as $group) {
            $default = Arr::get($group, 'is_default', 0) ? 1 : 0;
            if ($default) {
                if ($exists) {
                    throw new ResourceException('default group exists', ResourceException::ERR_RESOURCE_PROTECTED);
                }
            } else {
                $exists = true;
            }
            $columns[] = [
                'name' => $group['name'],
                'appraiser_id' => $userId,
                'performance_gid' => $currentGid,
                'year' => $year,
                'is_default' => $default,
                'month' => $month,
                'expiration_status' => $remainDays <= 4 ? Performance::EXPIRATION_STATUS_NO_APPRAISAL : Performance::EXPIRATION_STATUS_DEFAULT,
                'created_at' => $now,
                'updated_at' => $now,
            ];
            ++$currentGid;
        }

        $res = PerformanceGroup::insert($columns);
        PerformanceStatCache::app()->refreshOne(PerformanceStatCache::TYPE_APPRAISER_UN_GROUPED, $userId, $year, $month);
        return $res;
    }

    /**
     * 创建组。
     *
     * @param string $name
     * @param int $userId
     * @param bool $default
     * @return bool
     * @deprecated
     */
    public function createGroup(string $name, int $userId, bool $default = false): bool
    {
        // should I save it to redis?
        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();

        // 组创建的话一开始是不知道会放入哪些人的，因此组里面开始创建的时候，publisher_id 为空

        if ($default) {
            if (PerformanceGroup::where([
                'appraiser_id' => $userId,
                'is_default' => 1,
            ])->exists()) { // 如果存在默认组，则不允许创建
                return false;
            }
        }

        $sql = <<<'SQL'
INSERT INTO performance_groups (name, performance_gid, year, month, appraiser_id, is_default, unqualified_count,
                                total_count, publisher_id, publishment_id, history_remarks, is_closed, expiration_status, created_at, updated_at)
