public function appraiserGroups(): JsonResponse
{
    return $this->responseJsonSuccess([
        'groups' => $this->service->groups(Auth::id()),
    ]);
}
public function appraiserHistory(): JsonResponse
{
    return $this->responseJsonSuccess([
        'stats' => PerformanceStat::app()->historyGroupAppraiserStats([
            'appraiser_id' => Auth::id(),
        ]),
    ]);
}

/**
 * @apiName 绩效评价人创建绩效组
 *
 * @param Request $request
 * @return JsonResponse
 */
public function createGroup(Request $request): JsonResponse
{
    if (!$request->input('force_use', false)) {
        return $this->responseJsonFail('try calling deprecated api.');
    }
    return $this->responseJsonSuccess([
        'success' => $this->service->createGroup(
            $request->input('name', ''),
            Auth::id(),
            (bool)$request->input('is_default', false)
        ),
    ]);
}

public function createGroups(Request $request): JsonResponse
{
    return $this->responseJsonSuccess([
        'success' => $this->service->createGroups(
            $request->input('groups', []),
            Auth::id(),
        ),
    ]);
}

/**
 * @apiName 【绩效管理】更新绩效组
 *
 * @param Request $request
 * @throws ResourceException
 * @return JsonResponse
 */
public function updateGroup(Request $request): JsonResponse
{
    return $this->responseJsonSuccess([
        'success' => $this->service->updateGroup(
            Auth::id(),
            $request->input('performance_gid'),
            $request->only(['name', 'is_closed', 'total_count', 'unqualified_count'])
        ),
    ]);
}

/**
 * @apiName 【绩效管理】批量替换某一组内的所有成员。
 *
 * @param Request $request
 * @throws \Throwable
 * @return JsonResponse
 */
public function replaceGroupUsers(Request $request): JsonResponse
{
    return $this->responseJsonSuccess(['counts' => $this->service->replaceGroupUsers($request->input('groups'))]);
}

/**
 * @apiName 【绩效管理】员工端绩效评价页面
 *
 * @return JsonResponse
 */
public function appraisals(): JsonResponse
{
    [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
    return $this->responseJsonSuccess(['performances' => $this->service->appraisals(Auth::id(), $year, $month)]);
}

