/**
 * 检查指定用户是否有指定资源的所有权，用户的永久权限配置在 res_attrs 字段中，OA 端用户也需要配置一个 res_attrs 并加密
 * 存储到 OA 后端，中心服务器会解密并缓存在 Redis 中。
 *
 * @param ResourceMd $resMd 资源模型
 * @param null|int|OwnerMd $owner 传 int 表示用户id，不传表示当前 session 中的用户
 * @throws \App\Exceptions\CryptoException 缺少权限时会抛出异常
 * @throws \App\Exceptions\CommonException 查找 owner 时 owner type 不对时会抛出异常*@throws \App\Services\Exceptions\CryptoException
 * @return void 无异常即检查通过
 */
public function checkUserPermission(ResourceMd $resMd, $owner = null, bool $checkTokenIfFailed = false): void
{
    if (!is_object($owner)) {
        $owner = OwnerMd::find($owner);
    }

    // 该资源所有者默认有权限，一般是创建者或者资源本身（比如 sfuser 的所有者就是自己本身）
    if ($resMd->ownerType === $owner->ownerType && $resMd->ownerId === $owner->ownerId) {
        return;
    }

    $resAttrs = $owner->getResAttrs();

    if (!isset($resAttrs[$resMd->resType])) {
        if ($checkTokenIfFailed) {
            // owner ID 就是 sfuser，如果可见，返回，否则直接抛出异常
            if (AuthorizeService::app()->canSee($resMd, $owner->ownerId)) {
                return;
            }
        }
        throw new CryptoException('no permission for resType: '.$resMd->resType, CryptoException::ERR_CRYPTO_NO_PERMISSION_FOR_RES_TYPE);
    }

    // 某个资源类型的权限配置数组
    $permList = $resAttrs[$resMd->resType];
    foreach ($permList as $perm) {
        $permColumns = array_merge(['owner_id' => $resMd->ownerId], $resMd->permColumns);
        $flag = true;
        foreach ($permColumns as $key => $value) {
            $permLabelValues = $perm[$key] ?? [];
            // 任一权限标签不匹配，就算没有权限
            if ($permLabelValues !== 'all' && !in_array($value, Arr::wrap($permLabelValues))) { // 非数组的话 wrap 一下
                $flag = false;
                break;
            }
        }

        // 任意一项权限配置匹配成功，就算有权限
        if ($flag) {
            return;
        }
    }

    // 再检查一次
    if ($checkTokenIfFailed) {
        // owner ID 就是 sfuser，如果可见，返回，否则直接抛出异常
        if (AuthorizeService::app()->canSee($resMd, $owner->ownerId)) {
            return;
        }
    }

    throw new CryptoException('no permission for resType: '.$resMd->resType, CryptoException::ERR_CRYPTO_NO_PERMISSION_FOR_RES_TYPE);
}

