  1→<?php
  2→
  3→namespace App\Http\Controllers\Admin\Traits;
  4→
  5→use App\DailyReport\Service\RefreshDailyReportCcUsers;
  6→use App\Exceptions\ResourceException;
  7→use App\Exceptions\ServerException;
  8→use App\Jobs\UpdateReplaceFilterCache;
  9→use App\Jobs\UpdateSfuserCache;
 10→use App\Models\Sfuser;
 11→use App\Models\Staff;
 12→use App\Service\KnockService;
 13→use App\Service\Misc\SfuserHash2IdMapService;
 14→use App\Service\Misc\SfuserNicknameMapService;
 15→use App\Service\Misc\SfuserNotResignedHash2IdMapService;
 16→use Illuminate\Http\JsonResponse;
 17→use Illuminate\Support\Arr;
 18→use Illuminate\Support\Facades\Log;
 19→
 20→trait UpdateSfuserTrait
 21→{
 22→    /**
 23→     * 改变了下列字段会刷新中心服务器缓存。
 24→     *
 25→     * @var array|string[]
 26→     */
 27→    protected array $refreshCoreCacheFields = [
 28→        'nickname', 'email', 'department_id', 'password', 'knock_id', 'is_admin', 'active', 'supervisor_nickname',
 29→    ];
 30→
 31→    /**
 32→     * 更新用户。
 33→     *
 34→     * @param array $input
 35→     * @throws \Throwable
 36→     * @return \Illuminate\Http\JsonResponse
 37→     */
 38→    protected function updateSfuser(array $input): JsonResponse
 39→    {
 40→        $sfuser = Sfuser::active()->find($input['sfuser_id']);
 41→        Arr::forget($input, 'sfuser_id');
 42→
 43→        if (empty($sfuser)) {
 44→            return $this->responseJsonFail(__('system_api.sfuser_not_exists', ['id' => $input['sfuser_id']]), ResourceException::ERR_RESOURCE_MISSING);
 45→        }
 46→
 47→        $oldNicknameHash = $sfuser->nickname_hash;
 48→        $oldStatus = $sfuser->status;
 49→
 50→        // // 查重
 51→        // if (Sfuser::active()->where('id', '<>', $sfuser->id)->whereIn('nickname_hash', Arr::get($input, 'nickname_hash_filter', []))->exists()
 52→        //     || $input['nickname_replace_filter']) {
 53→        //     // 花名重复
 54→        //     return $this->responseJsonFail(__('system_api.sfuser_duplicated_nickname'), ResourceException::ERR_RESOURCE_DUPLICATED);
 55→        // }
 56→
 57→        // if (Sfuser::active()->where('id', '<>', $sfuser->id)->whereIn('email_hash', Arr::get($input, 'email_hash_filter', []))->exists()
 58→        //     || $input['email_replace_filter']) {
 59→        //     // 邮箱重复
 60→        //     return $this->responseJsonFail(__('system_api.sfuser_duplicated_email'), ResourceException::ERR_RESOURCE_DUPLICATED);
 61→        // }
 62→
 63→        if (Sfuser::active()->whereIn('email_hash', Arr::get($input, 'email_hash_filter', []))->exists() || $input['email_replace_filter']) {
 64→            // 邮箱重复
 65→            return $this->responseJsonFail(__('system_api.sfuser_duplicated_email'), ResourceException::ERR_RESOURCE_DUPLICATED);
 66→        }
 67→
 68→        // status is required
 69→        if ($sfuser->status != $input['status']) {
 70→            // 更新了 status
 71→            $input['active'] = $input['status'] == 'resignation' ? 0 : 1; // 离职禁用，其他开启
 72→        }
 73→
 74→        // 如果员工部门 ID 发生了变化
 75→
 76→        $departmentChange = false;
 77→        if (Arr::has($input, 'department_id')) {
 78→            $departmentChange = $sfuser->department_id != $input['department_id'];
 79→        }
 80→
 81→        if ($input) {
 82→            $updateColumns = [];
 83→            foreach ($this->refreshCoreCacheFields as $field) {
 84→                // 可能没有传递，是 null
 85→                if (Arr::get($input, $field, $sfuser->{$field}) != $sfuser->{$field}) {
 86→                    $updateColumns[] = $field;
 87→                    break;
 88→                }
 89→            }
 90→
 91→            db()->beginTransaction();
 92→            try {
 93→                $dSfuserId = $input['direct_supervisor_id'] ?? 0;
 94→                $supervisorId = $input['supervisor_id'] ?? 0;
 95→                $hrbpId = $input['hrbp_id'] ?? 0;
 96→                if ($dSfuserId && $dSfuserId != $sfuser->direct_supervisor_id) {
 97→                    Staff::initEmptyRecordIfNotExists($dSfuserId);
 98→                }
 99→                if ($supervisorId && $supervisorId != $sfuser->supervisor_id) {
100→                    Staff::initEmptyRecordIfNotExists($supervisorId);
101→                }
102→                if ($hrbpId && $hrbpId != $sfuser->hrbp_id) {
103→                    Staff::initEmptyRecordIfNotExists($hrbpId);
104→                }
105→                $sfuser->update(Arr::only($input, $this->allowedCreatedOrUpdatedColumns));
106→                db()->commit();
107→            } catch (\Throwable $e) {
108→                db()->rollBack();
109→                Log::error('failed to commit transaction', ['e' => $e->getMessage()]);
110→                return $this->responseJsonFail(__('my_api.db_update_fail'), ServerException::ERR_SERVER_DATABASE);
111→            }
112→
113→            $delete = Arr::get($input, 'is_closed');
114→
115→            // 上面事务提交了之后才能更新缓存
116→            if ($delete) { // 如果是删除，则采用 clear 策略
117→                UpdateSfuserCache::dispatchSync(Sfuser::STRATEGY_REMOVE, [
118→                    'updated_after' => time() - 300,
119→                ]);
120→            } elseif (count($updateColumns)) {
121→                UpdateSfuserCache::dispatchSync(Sfuser::STRATEGY_REPLACE, [
122→                    'updated_after' => time() - 300,
123→                ]);
124→            }
125→            // 无论删除还是更新，replace 缓存都需要重建
126→            UpdateReplaceFilterCache::dispatchSync('sfuser', $updateColumns);
127→
128→            if ($input['status'] == Sfuser::STATUS_RESIGNATION && $oldStatus != Sfuser::STATUS_RESIGNATION) {   // 离职
129→                SfuserNotResignedHash2IdMapService::app()->deleteOne($oldNicknameHash);
130→                RefreshDailyReportCcUsers::app()->addDismissedSfusers([$sfuser->id]);
131→            } elseif ($input['status'] != Sfuser::STATUS_RESIGNATION && $oldStatus == Sfuser::STATUS_RESIGNATION) { // 复职
132→                SfuserNotResignedHash2IdMapService::app()->refreshOne($sfuser->id, $sfuser->nickname_hash, $oldNicknameHash);
133→                RefreshDailyReportCcUsers::app()->reActive([$sfuser->id]);
134→            }
135→            if ($sfuser->nickname_hash != $oldNicknameHash) {
136→                $sfuser = $sfuser->fresh();
137→                SfuserHash2IdMapService::app()->refreshOne($sfuser->id, $sfuser->nickname_hash, $oldNicknameHash);
138→                SfuserNicknameMapService::app()->refreshOne($input['id'], $sfuser->nickname);
139→                if ($sfuser->status != Sfuser::STATUS_RESIGNATION) {
140→                    SfuserNotResignedHash2IdMapService::app()->refreshOne($sfuser->id, $sfuser->nickname_hash, $oldNicknameHash);
141→                }
142→            }
143→
144→            if (!$delete && $departmentChange) {
145→                KnockService::app()->sendMessageWhenDepartmentChange([$sfuser->id]);
146→            }
147→        }
148→
149→        return $this->responseJsonSuccess(['success' => true]);
150→    }
151→
152→    /**
153→     * @param array $input
154→     * @throws \Throwable
155→     * @return \Illuminate\Http\JsonResponse
156→     */
157→    protected function createSfuser(array $input): JsonResponse
158→    {
159→        $sfuser = Sfuser::find($input['sfuser_id']);
160→        if (!empty($sfuser)) {
161→            return $this->responseJsonFail(__('system_api.sfuser_exists', ['id' => $input['sfuser_id']]), ResourceException::ERR_RESOURCE_DUPLICATED);
162→        }
163→
164→        // 查重
165→        if (Sfuser::active()->whereIn('nickname_hash', Arr::get($input, 'nickname_hash_filter', []))->exists() || $input['nickname_replace_filter']) {
166→            // 花名重复
167→            return $this->responseJsonFail(__('system_api.sfuser_duplicated_nickname'), ResourceException::ERR_RESOURCE_DUPLICATED);
168→        }
169→
170→        if (Sfuser::active()->whereIn('email_hash', Arr::get($input, 'email_hash_filter', []))->exists() || $input['email_replace_filter']) {
171→            // 邮箱重复
172→            return $this->responseJsonFail(__('system_api.sfuser_duplicated_email'), ResourceException::ERR_RESOURCE_DUPLICATED);
173→        }
174→
175→        if ($input) {
176→            $input['id'] = $input['sfuser_id'];
177→            Arr::forget($input, 'sfuser_id');
178→            db()->beginTransaction();
179→            try {
180→                Sfuser::create(Arr::only($input, $this->allowedCreatedOrUpdatedColumns));
181→                if ($input['direct_supervisor_id'] ?? 0) {
182→                    Staff::initEmptyRecordIfNotExists($input['direct_supervisor_id']);
183→                }
184→
185→                if ($input['supervisor_id'] ?? 0) {
186→                    Staff::initEmptyRecordIfNotExists($input['supervisor_id']);
187→                }
188→
189→                if ($input['hrbp_id'] ?? 0) {
190→                    Staff::initEmptyRecordIfNotExists($input['hrbp_id']);
191→                }
192→
193→                db()->commit();
194→            } catch (\Throwable $e) {
195→                db()->rollBack();
196→                Log::error('failed to commit transaction', ['e' => $e->getMessage()]);
197→                return $this->responseJsonFail(__('my_api.db_update_fail'), ServerException::ERR_SERVER_DATABASE);
198→            }
199→            // sfuser cache
200→            UpdateSfuserCache::dispatchSync(Sfuser::STRATEGY_REPLACE, [
201→                'updated_after' => time() - 300,
202→            ]);
203→            // sfuser replace search cache
204→            UpdateReplaceFilterCache::dispatchSync('sfuser', array_keys(config('my_replace_search.sfuser')));
205→            SfuserHash2IdMapService::app()->refreshOne($input['id'], $input['nickname_hash']);
206→            SfuserNicknameMapService::app()->refreshOne($input['id'], $input['nickname']);
207→            if ($input['status'] != Sfuser::STATUS_RESIGNATION) {
208→                SfuserNotResignedHash2IdMapService::app()->refreshOne($input['id'], $input['nickname_hash']);
209→            }
210→        }
211→
212→        return $this->responseJsonSuccess(['success' => true, 'sfuser' => Sfuser::find($input['id'])->toArray()]);
213→    }
214→}
